import { create } from 'zustand'

export const useCountdownStore = create((set) => ({
    timeInput: {
        hours: '',
        minutes: '',
        seconds: ''
    },
    time: null,
    timeLeft: 0,
    initialSeconds: 0,
    isRunning: false,
    setTimeInput: (input) => set((state) => {
        const initial = Number((input.hours || 0) * 3600) + Number((input.minutes || 0) * 60) + Number((input.seconds || 0))
        return {
            timeInput: {
                ...state.timeInput,
                hours: input.hours,
                seconds: input.seconds,
                minutes: input.minutes
            },
            initialSeconds: initial,
            timeLeft: initial
        }
    }),
    setTimeLeft: (value) => set(() => ({
        timeLeft: value
    })),
    setIsRunning: (isRunning) => set(() => ({
        isRunning
    }))
}))
